    orgId: ORG_ID,
    role: "superAdmin",
  })
  console.log(`seed: promoting ${superAdmin.email} to superAdmin`)
} else {
  console.warn(
    `seed: SEED_SUPER_ADMIN_EMAIL=${superAdminEmail} did not match any creator — no super-admin seeded`,
  )
}
console.log(`seed: inserting ${membershipRows.length} memberships`)
await db.insert(memberships).values(membershipRows)

// Reviewer matrix: every (tier, subCat) cell gets at least one
// assignment from APPROVAL_REVIEWERS. Emails that don't resolve to a
// creator are skipped with a warning so a typo doesn't break the seed.
const reviewerRows = APPROVAL_REVIEWERS.flatMap((r, i) => {
  const reviewer = CREATORS.find((u) => u.email === r.reviewerEmail)
  if (!reviewer) {
    console.warn(
      `seed: approval reviewer email ${r.reviewerEmail} did not match any creator — skipping`,
    )
    return []
  }
  return [
    {
      id: `appr-rev-${i}`,
      tier: r.tier,
      subCat: r.subCat,
      userId: reviewer.id,
    },
  ]
})
console.log(`seed: inserting ${reviewerRows.length} approval reviewers`)
await db.insert(approvalReviewers).values(reviewerRows)

const extTagRows = EXTENSIONS.flatMap((e) =>
  e.tags.map((tagKey) => ({
    extensionId: `ext-${e.id}`,
    tagId: tagKey,
  })),
)
console.log(`seed: inserting ${extTagRows.length} extension-tag links`)
await db.insert(extensionTags).values(extTagRows)

// Email and slug → id maps shared by the approval-request block below
// and the editorial-collections block further down. Hoisted here so
// both sections look up against the same table.

// Dev-seed reviewer matrix for the approval workflow. Each row maps a
// (tier, subCat) cell to one or more reviewer emails. The seed script
// resolves emails to user ids against the rows it just inserted, so the
// emails here must match `CREATORS` in `scripts/seed.ts`. Real prod
// assignment happens through the super-admin matrix UI.
//
// Spread the assignments so every cell has at least one reviewer and the
// reviewer-queue page has non-empty content under each demo persona.

export const APPROVAL_REVIEWERS: ReadonlyArray<{
  tier: "productLine" | "company"
  subCat: string
  reviewerEmail: string
}> = [
  // Product-Line tier: per-line lieutenants.
  { tier: "productLine", subCat: "systemDesign", reviewerEmail: "amy@agentcenter.dev" },
  { tier: "productLine", subCat: "softDev",      reviewerEmail: "ben@agentcenter.dev" },
  { tier: "productLine", subCat: "testing",      reviewerEmail: "ben@agentcenter.dev" },
  { tier: "productLine", subCat: "network",      reviewerEmail: "cory@agentcenter.dev" },
  { tier: "productLine", subCat: "embedded",     reviewerEmail: "cory@agentcenter.dev" },
  { tier: "productLine", subCat: "cloud",        reviewerEmail: "dao@agentcenter.dev" },
  { tier: "productLine", subCat: "docs",         reviewerEmail: "eli@agentcenter.dev" },
  { tier: "productLine", subCat: "data",         reviewerEmail: "eli@agentcenter.dev" },
  { tier: "productLine", subCat: "vcs",          reviewerEmail: "fei@agentcenter.dev" },

  // Company tier: a smaller circle of senior reviewers.
  { tier: "company", subCat: "systemDesign", reviewerEmail: "amy@agentcenter.dev" },
  { tier: "company", subCat: "softDev",      reviewerEmail: "amy@agentcenter.dev" },
  { tier: "company", subCat: "testing",      reviewerEmail: "amy@agentcenter.dev" },
  { tier: "company", subCat: "network",      reviewerEmail: "dao@agentcenter.dev" },
  { tier: "company", subCat: "embedded",     reviewerEmail: "dao@agentcenter.dev" },
  { tier: "company", subCat: "cloud",        reviewerEmail: "dao@agentcenter.dev" },
  { tier: "company", subCat: "docs",         reviewerEmail: "fei@agentcenter.dev" },
  { tier: "company", subCat: "data",         reviewerEmail: "fei@agentcenter.dev" },
  { tier: "company", subCat: "vcs",          reviewerEmail: "fei@agentcenter.dev" },
]

// First entry in `CREATORS` (amy) gets the super-admin membership unless
// `SEED_SUPER_ADMIN_EMAIL` overrides at runtime.
export const DEFAULT_SUPER_ADMIN_EMAIL = "amy@agentcenter.dev"

// Dev-seed approval requests for the approval workflow. Covers every
// state the publisher and reviewer UIs render, so a freshly-seeded dev
// DB lights up `/admin/approvals`, the publisher dashboard's "Awaiting
// review" pill, and `/profile?section=requests` without any manual
// submit/decide cycle. Mirrors `approval-reviewers.ts`'s shape: emails
// and slugs are resolved by `scripts/seed.ts` against the rows it just
// inserted, with warnings for any reference that doesn't match.
//
// Invariant: at most one pending row per extension. The orchestrator
// guards this at runtime; the seed must not break it on first load.

export interface SeedApprovalRequest {
  extensionSlug: string
  publisherEmail: string
  requestedTier: "productLine" | "company"
  subCat: string
  status: "pending" | "approved" | "rejected"
  reason?: string
  decidedByEmail?: string
  reviewerNote?: string
}

export const APPROVAL_REQUESTS: ReadonlyArray<SeedApprovalRequest> = [
  {
    extensionSlug: "calendar-agent",
    publisherEmail: "cory@agentcenter.dev",
    requestedTier: "company",
    subCat: "data",
    status: "pending",
    reason:
      "Calendar coordination has become load-bearing across the org — promoting this would let teams trust it without a second look.",
  },
  {
    extensionSlug: "mqtt-bridge",
    publisherEmail: "dao@agentcenter.dev",
    requestedTier: "productLine",
    subCat: "network",
    status: "pending",
    reason: "Already used by every embedded squad in the IoT product line.",
  },
  {
    extensionSlug: "summarize",
    publisherEmail: "eli@agentcenter.dev",
    requestedTier: "company",
    subCat: "docs",
    status: "approved",
    decidedByEmail: "fei@agentcenter.dev",
  },
  {
    extensionSlug: "explain",
    publisherEmail: "fei@agentcenter.dev",
    requestedTier: "company",
    subCat: "softDev",
    status: "rejected",
    decidedByEmail: "amy@agentcenter.dev",
    reviewerNote:
      "Needs a maintainer contact in the manifest before company-level review.",
  },
]

const userIdByEmail = new Map(CREATORS.map((u) => [u.email, u.id]))
const extIdBySlug = new Map(extRows.map((r) => [r.slug, r.id]))

// Approval requests — a small spread covering every UI state. Pending
// rows light up the reviewer queue; the approved row also stamps the
// parent extension's officialTier so the publisher's view matches what
// the real workflow's transactional approve would have produced. NOTE:
// these rows are inserted directly, bypassing `submitRequest`, so no
// `extension/approval.requested` Inngest event fires for them — that's
// expected on a fresh seed and not a bug in the workflow.
const approvalRequestRows: {
  id: string
  extensionId: string
  requestedTier: "productLine" | "company"
  subCat: string
  requestedByUserId: string
  reason: string | null
  status: "pending" | "approved" | "rejected"
  decidedByUserId: string | null
  decidedAt: Date | null
  reviewerNote: string | null
}[] = []
const officialTierStamps: { extensionId: string; tier: "productLine" | "company" }[] = []
for (const [i, r] of APPROVAL_REQUESTS.entries()) {
  const extensionId = extIdBySlug.get(r.extensionSlug)
  if (!extensionId) {
    console.warn(
      `seed: approval request #${i} references unknown extension slug "${r.extensionSlug}" — skipping`,
    )
    continue
  }
  const publisherId = userIdByEmail.get(r.publisherEmail)
  if (!publisherId) {
    console.warn(
      `seed: approval request #${i} references unknown publisher ${r.publisherEmail} — skipping`,
    )
    continue
  }
  let decidedByUserId: string | null = null
  if (r.decidedByEmail) {
    decidedByUserId = userIdByEmail.get(r.decidedByEmail) ?? null
    if (!decidedByUserId) {
      console.warn(
        `seed: approval request #${i} references unknown decider ${r.decidedByEmail} — leaving decidedByUserId null`,
      )
    }
  }
  const isDecided = r.status === "approved" || r.status === "rejected"
  // Defensive: the orchestrator enforces at-most-one-pending-per-extension
  // at runtime; the seed must boot the marketplace in a state that already
  // honors it. The current data file picks distinct extensions for the two
  // pending rows, but a future edit could silently violate the invariant
  // without this guard — skip with a warning instead.
  if (
    r.status === "pending" &&
    approvalRequestRows.some(
      (existing) =>
        existing.extensionId === extensionId && existing.status === "pending",
    )
  ) {
    console.warn(
      `seed: approval request #${i} would be a second pending row for "${r.extensionSlug}" — skipping to preserve the at-most-one-pending invariant`,
    )
    continue
  }
  approvalRequestRows.push({
    id: `appr-req-${i}`,
    extensionId,
    requestedTier: r.requestedTier,
    subCat: r.subCat,
    requestedByUserId: publisherId,
    reason: r.reason ?? null,
    status: r.status,
    decidedByUserId,
    decidedAt: isDecided ? new Date() : null,
    reviewerNote: r.reviewerNote ?? null,
  })
  if (r.status === "approved") {
    officialTierStamps.push({ extensionId, tier: r.requestedTier })
  }
}
if (approvalRequestRows.length > 0) {
  console.log(`seed: inserting ${approvalRequestRows.length} approval requests`)
  await db.insert(approvalRequests).values(approvalRequestRows)
}
for (const stamp of officialTierStamps) {
  await db
    .update(extensions)
    .set({ officialTier: stamp.tier })
