describe("insertReviewer + listMatrix", () => {
  it("persists reviewer assignments and joins with user display fields", async () => {
    await reviewersRepo.insertReviewer(db, {
      id: "rev-1",
      tier: "productLine",
      subCat: "softDev",
      userId: "u-alice",
    })
    await reviewersRepo.insertReviewer(db, {
      id: "rev-2",
      tier: "company",
      subCat: "docs",
      userId: "u-bob",
    })

    const matrix = await reviewersRepo.listMatrix(db)
    expect(matrix).toHaveLength(2)
    const cells = matrix.map((r) => ({
      tier: r.tier,
      subCat: r.subCat,
      userEmail: r.userEmail,
      userName: r.userName,
    }))
    expect(cells).toContainEqual({
      tier: "productLine",
      subCat: "softDev",
      userEmail: "alice@example.com",
      userName: "Alice",
    })
    expect(cells).toContainEqual({
      tier: "company",
      subCat: "docs",
      userEmail: "bob@example.com",
      userName: "Bob",
    })
  })

  it("orders by (tier, subCat, email)", async () => {
    await reviewersRepo.insertReviewer(db, {
      id: "rev-1",
