    const me = await $fetch("/api/internal/admin/me", {
      headers: headers as Record<string, string>,
    })
    if (!me.isReviewer) {
      return navigateTo(localePath("/"))
    }
  } catch {
    return navigateTo(localePath("/sign-in"))
